mapper.insert:
INSERT INTO outbox_event (
    event_id, aggregate_type, aggregate_id, event_type, schema_version,
    payload, status, available_at
) VALUES (
    #{eventId}, #{aggregateType}, #{aggregateId}, #{eventType}, #{schemaVersion},
    #{payload}, #{status}, #{availableAt}
)

mapper.select:
SELECT * FROM outbox_event
WHERE status = 'NEW' AND available_at <= #{now}
  AND (claim_until IS NULL OR claim_until <= #{now})
ORDER BY id
LIMIT #{limit}

mapper.update:
UPDATE outbox_event
SET claimed_by = #{claimedBy}, claim_until = #{claimUntil},
    publish_attempts = publish_attempts + 1, updated_at = #{now}
WHERE event_id = #{eventId} AND status = 'NEW' AND available_at <= #{now}
  AND (claim_until IS NULL OR claim_until <= #{now})

UPDATE outbox_event
SET status = 'PUBLISHED', published_at = #{publishedAt}, claimed_by = NULL,
    claim_until = NULL, last_error = NULL, updated_at = #{publishedAt}
WHERE event_id = #{eventId} AND status = 'NEW' AND claimed_by = #{claimedBy}
